/**
 * E-Menum Product Theme - Main Stylesheet
 *
 * Mobile-first customer-facing menu theme optimized for:
 * - Touch interactions (48px minimum touch targets)
 * - Fast loading (minimal CSS, critical path)
 * - Accessibility (WCAG 2.1 AA compliance)
 * - Dark mode support
 * - Brand customization via CSS variables
 *
 * Following FRONTEND_ARCHITECTURE.md and COMPONENT_PATTERNS.md patterns.
 */

/* ==========================================================================
   1. CSS CUSTOM PROPERTIES (Design Tokens)
   ========================================================================== */

:root {
  /* === BRAND COLORS (Customizable per restaurant) === */
  --brand-primary: #2563eb;
  --brand-primary-light: #3b82f6;
  --brand-primary-dark: #1d4ed8;
  --brand-primary-subtle: #dbeafe;
  --brand-secondary: #7c3aed;
  --brand-accent: #f59e0b;
  --brand-text-on-primary: #ffffff;

  /* === SEMANTIC COLORS === */
  --color-success: #059669;
  --color-success-light: #10b981;
  --color-success-subtle: #d1fae5;
  --color-warning: #d97706;
  --color-warning-light: #f59e0b;
  --color-warning-subtle: #fef3c7;
  --color-error: #dc2626;
  --color-error-light: #ef4444;
  --color-error-subtle: #fee2e2;
  --color-info: #2563eb;
  --color-info-light: #3b82f6;
  --color-info-subtle: #dbeafe;

  /* === SURFACE COLORS (Light Mode) === */
  --surface-background: #f8fafc;
  --surface-card: #ffffff;
  --surface-elevated: #f1f5f9;
  --surface-overlay: rgba(0, 0, 0, 0.5);

  /* === TEXT COLORS (Light Mode) === */
  --text-primary: #0f172a;
  --text-secondary: #475569;
  --text-muted: #94a3b8;
  --text-inverse: #ffffff;

  /* === BORDER COLORS === */
  --border-color: #e2e8f0;
  --border-color-strong: #cbd5e1;

  /* === SHADOWS === */
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -2px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -4px rgba(0, 0, 0, 0.1);
  --shadow-xl: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 8px 10px -6px rgba(0, 0, 0, 0.1);

  /* === SPACING === */
  --space-1: 0.25rem;  /* 4px */
  --space-2: 0.5rem;   /* 8px */
  --space-3: 0.75rem;  /* 12px */
  --space-4: 1rem;     /* 16px */
  --space-5: 1.25rem;  /* 20px */
  --space-6: 1.5rem;   /* 24px */
  --space-8: 2rem;     /* 32px */

  /* === BORDER RADIUS === */
  --radius-sm: 0.25rem;  /* 4px */
  --radius-md: 0.5rem;   /* 8px */
  --radius-lg: 0.75rem;  /* 12px */
  --radius-xl: 1rem;     /* 16px */
  --radius-2xl: 1.5rem;  /* 24px */
  --radius-full: 9999px;

  /* === TYPOGRAPHY === */
  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto,
    'Helvetica Neue', Arial, sans-serif;

  /* === TRANSITIONS === */
  --transition-fast: 100ms ease-out;
  --transition-normal: 200ms ease-out;
  --transition-slow: 300ms ease-out;

  /* === Z-INDEX SCALE === */
  --z-sticky: 20;
  --z-fixed: 30;
  --z-modal-backdrop: 40;
  --z-modal: 50;
  --z-toast: 60;

  /* === TOUCH TARGETS === */
  --touch-target-min: 48px;
}

/* === DARK MODE === */
[data-theme="dark"] {
  /* Surface Colors */
  --surface-background: #0f172a;
  --surface-card: #1e293b;
  --surface-elevated: #334155;
  --surface-overlay: rgba(0, 0, 0, 0.7);

  /* Text Colors */
  --text-primary: #f8fafc;
  --text-secondary: #cbd5e1;
  --text-muted: #64748b;
  --text-inverse: #0f172a;

  /* Border Colors */
  --border-color: #334155;
  --border-color-strong: #475569;

  /* Semantic Colors (Dark variants) */
  --color-success-subtle: rgba(16, 185, 129, 0.2);
  --color-warning-subtle: rgba(245, 158, 11, 0.2);
  --color-error-subtle: rgba(239, 68, 68, 0.2);
  --color-info-subtle: rgba(59, 130, 246, 0.2);

  /* Brand Colors (Dark variants) */
  --brand-primary-subtle: rgba(59, 130, 246, 0.2);

  /* Shadows (subtle in dark mode) */
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.3);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.5);
  --shadow-xl: 0 20px 25px -5px rgba(0, 0, 0, 0.5);
}

/* === HIGH CONTRAST MODE === */
@media (prefers-contrast: high) {
  :root {
    --text-primary: #000000;
    --text-secondary: #1a1a1a;
    --border-color: #000000;
  }

  [data-theme="dark"] {
    --text-primary: #ffffff;
    --text-secondary: #f0f0f0;
    --border-color: #ffffff;
  }
}

/* === REDUCED MOTION === */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* ==========================================================================
   2. BASE STYLES
   ========================================================================== */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  -webkit-text-size-adjust: 100%;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  scroll-behavior: smooth;
  /* Prevent pull-to-refresh on mobile */
  overscroll-behavior-y: none;
}

body {
  font-family: var(--font-sans);
  font-size: 1rem;
  line-height: 1.6;
  color: var(--text-primary);
  background-color: var(--surface-background);
  min-height: 100vh;
  min-height: 100dvh; /* Dynamic viewport height for mobile */
}

/* Typography */
h1, h2, h3, h4, h5, h6 {
  font-weight: 600;
  line-height: 1.3;
  color: var(--text-primary);
}

h1 { font-size: 1.5rem; }
h2 { font-size: 1.25rem; }
h3 { font-size: 1.125rem; }
h4 { font-size: 1rem; }

p {
  margin-bottom: 0.75rem;
}

a {
  color: var(--brand-primary);
  text-decoration: none;
  -webkit-tap-highlight-color: transparent;
}

a:focus-visible {
  outline: 2px solid var(--brand-primary);
  outline-offset: 2px;
  border-radius: var(--radius-sm);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

/* ==========================================================================
   3. ACCESSIBILITY
   ========================================================================== */

/* Skip Link */
.skip-link {
  position: absolute;
  top: -100%;
  left: 0;
  z-index: 9999;
  padding: 1rem 1.5rem;
  background-color: var(--brand-primary);
  color: var(--brand-text-on-primary);
  font-weight: 500;
  text-decoration: none;
  border-radius: 0 0 var(--radius-md) 0;
  transition: top var(--transition-fast);
}

.skip-link:focus {
  top: 0;
  outline: 2px solid var(--brand-text-on-primary);
  outline-offset: 2px;
}

/* Screen Reader Only */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Focus Visible */
:focus-visible {
  outline: 2px solid var(--brand-primary);
  outline-offset: 2px;
}

:focus:not(:focus-visible) {
  outline: none;
}

/* ==========================================================================
   4. COMPONENT STYLES
   ========================================================================== */

/* === BUTTONS === */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 0.75rem 1.25rem;
  font-size: 0.9375rem;
  font-weight: 500;
  font-family: inherit;
  line-height: 1.4;
  text-align: center;
  text-decoration: none;
  white-space: nowrap;
  cursor: pointer;
  user-select: none;
  border: 1px solid transparent;
  border-radius: var(--radius-lg);
  transition: all var(--transition-fast);
  min-height: var(--touch-target-min);
  -webkit-tap-highlight-color: transparent;
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

.btn:active:not(:disabled) {
  transform: scale(0.98);
}

/* Button Variants */
.btn-primary {
  background-color: var(--brand-primary);
  color: var(--brand-text-on-primary);
  border-color: var(--brand-primary);
}

.btn-primary:hover:not(:disabled) {
  background-color: var(--brand-primary-dark);
  border-color: var(--brand-primary-dark);
}

.btn-secondary {
  background-color: transparent;
  color: var(--text-primary);
  border-color: var(--border-color-strong);
}

.btn-secondary:hover:not(:disabled) {
  background-color: var(--surface-elevated);
}

.btn-ghost {
  background-color: transparent;
  color: var(--text-secondary);
  border-color: transparent;
}

.btn-ghost:hover:not(:disabled) {
  background-color: var(--surface-elevated);
  color: var(--text-primary);
}

/* Button Sizes */
.btn-sm {
  padding: 0.5rem 0.875rem;
  font-size: 0.875rem;
  min-height: 40px;
}

.btn-icon {
  padding: 0.75rem;
  min-width: var(--touch-target-min);
}

.btn-icon.btn-sm {
  padding: 0.5rem;
  min-width: 40px;
  min-height: 40px;
}

/* === BADGES === */
.badge {
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  padding: 0.25rem 0.625rem;
  font-size: 0.75rem;
  font-weight: 500;
  line-height: 1.2;
  border-radius: var(--radius-full);
  white-space: nowrap;
}

.badge-primary {
  background-color: var(--brand-primary-subtle);
  color: var(--brand-primary);
}

.badge-success {
  background-color: var(--color-success-subtle);
  color: var(--color-success);
}

.badge-warning {
  background-color: var(--color-warning-subtle);
  color: var(--color-warning);
}

.badge-error {
  background-color: var(--color-error-subtle);
  color: var(--color-error);
}

.badge-neutral {
  background-color: var(--surface-elevated);
  color: var(--text-secondary);
}

/* === FORMS === */
.form-input,
.form-select,
.form-textarea {
  display: block;
  width: 100%;
  padding: 0.75rem 1rem;
  font-size: 1rem;
  font-family: inherit;
  line-height: 1.5;
  color: var(--text-primary);
  background-color: var(--surface-card);
  background-clip: padding-box;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  transition: border-color var(--transition-fast), box-shadow var(--transition-fast);
  min-height: var(--touch-target-min);
  -webkit-appearance: none;
}

.form-input:focus,
.form-select:focus,
.form-textarea:focus {
  border-color: var(--brand-primary);
  box-shadow: 0 0 0 3px var(--brand-primary-subtle);
  outline: none;
}

.form-input::placeholder,
.form-textarea::placeholder {
  color: var(--text-muted);
}

.form-checkbox,
.form-radio {
  width: 1.25rem;
  height: 1.25rem;
  cursor: pointer;
  accent-color: var(--brand-primary);
}

/* === PRODUCT CARDS === */
.product-card {
  display: flex;
  flex-direction: column;
  background-color: var(--surface-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-xl);
  overflow: hidden;
  box-shadow: var(--shadow-sm);
  transition: box-shadow var(--transition-normal), transform var(--transition-normal);
}

.product-card:hover {
  box-shadow: var(--shadow-md);
}

.product-card-image {
  position: relative;
  aspect-ratio: 4 / 3;
  overflow: hidden;
  background-color: var(--surface-elevated);
}

.product-card-body {
  display: flex;
  flex-direction: column;
  padding: 1rem;
  flex: 1;
}

.product-card-compact {
  flex-direction: row;
}

.product-card-compact .product-card-image {
  width: 100px;
  height: 100px;
  aspect-ratio: 1;
  flex-shrink: 0;
}

.product-card-compact .product-card-body {
  flex-direction: row;
  align-items: center;
  gap: 1rem;
}

.product-card-unavailable {
  opacity: 0.7;
}

/* === LINE CLAMP === */
.line-clamp-2 {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.line-clamp-3 {
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

/* === SKELETON LOADING === */
.skeleton {
  background: linear-gradient(
    90deg,
    var(--surface-elevated) 25%,
    var(--surface-card) 50%,
    var(--surface-elevated) 75%
  );
  background-size: 200% 100%;
  animation: skeleton-pulse 1.5s ease-in-out infinite;
  border-radius: var(--radius-md);
}

@keyframes skeleton-pulse {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

/* ==========================================================================
   5. UTILITY CLASSES
   ========================================================================== */

/* Display */
.hidden { display: none !important; }
.block { display: block; }
.flex { display: flex; }
.inline-flex { display: inline-flex; }

/* Flexbox */
.flex-col { flex-direction: column; }
.flex-wrap { flex-wrap: wrap; }
.items-start { align-items: flex-start; }
.items-center { align-items: center; }
.items-end { align-items: flex-end; }
.justify-start { justify-content: flex-start; }
.justify-center { justify-content: center; }
.justify-end { justify-content: flex-end; }
.justify-between { justify-content: space-between; }
.flex-1 { flex: 1 1 0%; }
.flex-shrink-0 { flex-shrink: 0; }

/* Gap */
.gap-1 { gap: var(--space-1); }
.gap-2 { gap: var(--space-2); }
.gap-3 { gap: var(--space-3); }
.gap-4 { gap: var(--space-4); }

/* Padding */
.p-3 { padding: var(--space-3); }
.p-4 { padding: var(--space-4); }
.px-4 { padding-left: var(--space-4); padding-right: var(--space-4); }
.py-2 { padding-top: var(--space-2); padding-bottom: var(--space-2); }

/* Margin */
.m-0 { margin: 0; }
.mt-1 { margin-top: var(--space-1); }
.mt-2 { margin-top: var(--space-2); }
.mt-3 { margin-top: var(--space-3); }
.mt-4 { margin-top: var(--space-4); }
.mb-2 { margin-bottom: var(--space-2); }
.mb-4 { margin-bottom: var(--space-4); }
.ml-auto { margin-left: auto; }

/* Text */
.text-xs { font-size: 0.75rem; }
.text-sm { font-size: 0.875rem; }
.text-base { font-size: 1rem; }
.text-lg { font-size: 1.125rem; }
.text-xl { font-size: 1.25rem; }

.font-medium { font-weight: 500; }
.font-semibold { font-weight: 600; }
.font-bold { font-weight: 700; }

.text-center { text-align: center; }
.truncate {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Colors */
.text-text-primary { color: var(--text-primary); }
.text-text-secondary { color: var(--text-secondary); }
.text-text-muted { color: var(--text-muted); }
.text-brand-primary { color: var(--brand-primary); }

.bg-surface-background { background-color: var(--surface-background); }
.bg-surface-card { background-color: var(--surface-card); }
.bg-surface-elevated { background-color: var(--surface-elevated); }

/* Borders */
.border { border: 1px solid var(--border-color); }
.border-b { border-bottom: 1px solid var(--border-color); }
.border-t { border-top: 1px solid var(--border-color); }
.border-border-color { border-color: var(--border-color); }

.rounded-lg { border-radius: var(--radius-lg); }
.rounded-xl { border-radius: var(--radius-xl); }
.rounded-2xl { border-radius: var(--radius-2xl); }
.rounded-full { border-radius: var(--radius-full); }

/* Shadows */
.shadow-sm { box-shadow: var(--shadow-sm); }
.shadow-md { box-shadow: var(--shadow-md); }
.shadow-lg { box-shadow: var(--shadow-lg); }

/* Position */
.relative { position: relative; }
.absolute { position: absolute; }
.fixed { position: fixed; }
.sticky { position: sticky; }
.inset-0 { inset: 0; }
.top-0 { top: 0; }
.right-0 { right: 0; }
.bottom-0 { bottom: 0; }
.left-0 { left: 0; }

/* Sizing */
.w-full { width: 100%; }
.h-full { height: 100%; }
.min-h-screen {
  min-height: 100vh;
  min-height: 100dvh;
}
.min-w-0 { min-width: 0; }
.max-w-lg { max-width: 32rem; }
.max-w-2xl { max-width: 42rem; }

/* Overflow */
.overflow-auto { overflow: auto; }
.overflow-hidden { overflow: hidden; }
.overflow-y-auto { overflow-y: auto; }
.overflow-x-auto { overflow-x: auto; }

/* Cursor */
.cursor-pointer { cursor: pointer; }

/* Transitions */
.transition-colors {
  transition-property: color, background-color, border-color;
  transition-duration: 200ms;
  transition-timing-function: ease-out;
}

.transition-all {
  transition-property: all;
  transition-duration: 200ms;
  transition-timing-function: ease-out;
}

/* Z-Index */
.z-20 { z-index: 20; }
.z-30 { z-index: 30; }
.z-40 { z-index: 40; }
.z-50 { z-index: 50; }

/* ==========================================================================
   6. RESPONSIVE UTILITIES
   ========================================================================== */

@media (min-width: 640px) {
  .sm\:hidden { display: none; }
  .sm\:block { display: block; }
  .sm\:inline { display: inline; }
  .sm\:flex { display: flex; }
  .sm\:inline-flex { display: inline-flex; }
}

@media (min-width: 768px) {
  .md\:hidden { display: none; }
  .md\:block { display: block; }
  .md\:flex { display: flex; }
}

/* ==========================================================================
   7. PRODUCT GRID
   ========================================================================== */

.product-grid {
  display: grid;
  grid-template-columns: repeat(1, minmax(0, 1fr));
  gap: 1rem;
  padding: 1rem;
}

@media (min-width: 640px) {
  .product-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (min-width: 1024px) {
  .product-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

/* ==========================================================================
   8. CATEGORY SECTION
   ========================================================================== */

.category-section {
  scroll-margin-top: 120px; /* Account for sticky header and nav */
}

.category-section-title {
  font-size: 1.25rem;
  font-weight: 600;
  color: var(--text-primary);
  padding: 1rem;
  padding-bottom: 0.5rem;
  position: sticky;
  top: 112px; /* 64px header + 48px category nav */
  background-color: var(--surface-background);
  z-index: 10;
}

/* ==========================================================================
   9. SAFE AREA INSETS (for mobile notches)
   ========================================================================== */

@supports (padding-bottom: env(safe-area-inset-bottom)) {
  .pb-safe {
    padding-bottom: calc(1rem + env(safe-area-inset-bottom));
  }

  /* Add extra padding for floating cart button */
  main {
    padding-bottom: calc(6rem + env(safe-area-inset-bottom));
  }
}

/* ==========================================================================
   10. PRINT STYLES
   ========================================================================== */

@media print {
  .no-print { display: none !important; }

  body {
    background: white;
    color: black;
  }

  .product-card {
    box-shadow: none;
    border: 1px solid #ccc;
    break-inside: avoid;
  }
}
